using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalLength { get; set; }

    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService : IDocumentSummarizationService
{
    // Common English stop words excluded from scoring
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "in", "on", "at", "to", "for",
        "of", "with", "by", "from", "is", "are", "was", "were", "be", "been",
        "being", "have", "has", "had", "do", "does", "did", "will", "would",
        "could", "should", "may", "might", "shall", "can", "need", "it", "its",
        "this", "that", "these", "those", "i", "you", "he", "she", "we", "they",
        "me", "him", "her", "us", "them", "my", "your", "his", "our", "their",
        "not", "no", "nor", "so", "if", "then", "than", "too", "very", "just",
        "about", "above", "after", "again", "all", "also", "am", "any", "as",
        "because", "before", "between", "both", "each", "few", "get", "got",
        "here", "how", "into", "more", "most", "much", "must", "new", "now",
        "only", "other", "out", "over", "own", "same", "some", "such", "there",
        "through", "under", "up", "what", "when", "where", "which", "while",
        "who", "whom", "why", "down"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences, preserving original order
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i)
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string
        var raw = SentenceBoundary().Split(text);
        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                freq[word] = freq.TryGetValue(word, out var count) ? count + 1 : 1;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Count > 0 ? wordFrequencies.Values.Max() : 1;

        return sentences.Select((sentence, index) =>
        {
            var words = TokenizeWords(sentence);
            if (words.Length == 0)
                return (index, Score: 0.0);

            double score = words
                .Where(w => !StopWords.Contains(w) && w.Length >= 2)
                .Sum(w => wordFrequencies.TryGetValue(w, out var f) ? (double)f / maxFreq : 0);

            // Normalize by word count to avoid bias toward long sentences
            return (index, Score: score / words.Length);
        }).ToList();
    }

    private static string[] TokenizeWords(string text) =>
        WordToken().Matches(text)
            .Select(m => m.Value)
            .ToArray();

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordToken();
}

namespace DocSummary.Services;

public interface IDocumentSummarizationService
{
    string Summarize(string documentText, int maxSentences);
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizationService _summarizer;

    public SummarizeController(IDocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

